              ) : (
                <form onSubmit={handleSubmit} className="space-y-5">
                  <div>
                    <label htmlFor="name" className="block text-sm font-medium text-slate-400 mb-1.5">Nome Completo</label>
                    <input
                      type="text"
                      id="name"
                      name="name"
                      required
